1.query:
fetch events
| filter matchesValue(event.name, "Process memory Saturation") and  matchesPhrase(display_id, "*P*") and  matchesValue(event.status_transition, "CREATED") or matchesValue(event.name, "Process CPU Saturation") and  matchesPhrase(display_id, "*P*") and  matchesValue(event.status_transition, "CREATED") or matchesValue(event.name, "Low Storage Warning") and  matchesPhrase(display_id, "*P*") and  matchesValue(event.status_transition, "CREATED")  or matchesPhrase(event.name, "*Remediation -*") 
//| filter matchesPhrase(display_id, "*P*") 
//| filter matchesValue(event.status_transition, "CREATED")
| fieldsadd Problemid=concat("🔥 " ,display_id, " ")
//| filter dt.davis.is_duplicate==false
| fieldsadd msg=if(matchesPhrase(event.name, "*Remediation -*") == true, concat("♻️ ", event.name), else:if(matchesPhrase(event.name, "*Remediation Email*") == true, concat("📨 ", event.name), else:concat(Problemid,event.name)))
| fields  timestamp, msg, event.id, workflow, Url
| fieldsadd url=if(matchesPhrase(msg, "*Remediation -*") == true, workflow, else:concat("https://kyw96254.apps.dynatrace.com/ui/apps/dynatrace.davis.problems/problem/",event.id)), urlcl=concat("https://kyw96254.apps.dynatrace.com/ui/apps/dynatrace.classic.problems/#problems/problemdetails;gtf=-2h;gf=all;pid=",event.id)
| summarize time=takeFirst(timestamp), Message=collectDistinct(msg),url=takefirst(url),snowurl=takefirst(Url),by:{msg}
| sort time desc
|  fieldsRemove msg

