input.script:
import { documentsClient } from "@dynatrace-sdk/client-document";
import { getEnvironmentUrl } from '@dynatrace-sdk/app-environment';


export default async function({executionId}) {      
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  let content = input.dashboardjson
  let content_blob = new Blob([JSON.stringify(content, null, 2)], {
    type: 'application/json',
  })

  let config = {
    "body": {
      "name": ""+input.dashboardname+"",
      "type": "dashboard",
      "content": content_blob
      }
  }

  let create = await documentsClient.createDocument(config)



  let env_url = getEnvironmentUrl()
  let dashboard_url = env_url+"/ui/apps/dynatrace.dashboards/dashboard/"+ create.id



  return {
           "dashboard_url": dashboard_url,
           "dashboard_name": input.dashboardname,
           "dashboard_content": create 
          };
}
